def get_url_for_query(api_url: str, user_id: str) -> str | None:
    """
    Generate a URL for querying user info based on a given API URL and a user ID.
    The expected URL is the API URL concatenated with the user ID.
    If the user ID is empty or invalid, the function returns None.
    """
    # Validate user_id: must be a non-empty string containing only alphanumeric characters, hyphens, or underscores
    if not isinstance(user_id, str) or not user_id:
        return None
    if not all(c.isalnum() or c in ('_', '-') for c in user_id):
        return None

    # Basic validation for api_url (optional but safe)
    if not isinstance(api_url, str) or not api_url:
        return None

    # Ensure exactly one slash between api_url and user_id
    if api_url.endswith('/'):
        return api_url + user_id
    else:
        return api_url + '/' + user_id

