    ast.Index,  # Python <3.9
    ast.Slice,
    ast.ExtSlice,
}

# For Python 3.8+, ast.Num, ast.Str, etc. are deprecated and mapped to ast.Constant.
# We'll add them for backward compatibility.
ALLOWED_NODES.update({ast.Num, ast.Str, ast.Bytes, ast.NameConstant, ast.Ellipsis})

def _check_node(node):
    """Recursively check that all nodes in the AST are allowed."""
    if type(node) not in ALLOWED_NODES:
        raise ValueError(f"Disallowed expression: {type(node).__name__}")
    for child in ast.iter_child_nodes(node):
        _check_node(child)

def _evaluate_node(node, namespace):
    """Recursively evaluate an AST node in a restricted namespace."""
    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Name):
        if node.id in namespace:
            return namespace[node.id]
        raise ValueError(f"Name '{node.id}' is not defined")
    elif isinstance(node, ast.UnaryOp):
        operand = _evaluate_node(node.operand, namespace)
        op = node.op
        if isinstance(op, ast.UAdd):
            return +operand
        elif isinstance(op, ast.USub):
            return -operand
        elif isinstance(op, ast.Not):
            return not operand
        elif isinstance(op, ast.Invert):
            return ~operand
        else:
            raise ValueError(f"Unsupported unary operator: {type(op).__name__}")
    elif isinstance(node, ast.BinOp):
        left = _evaluate_node(node.left, namespace)
        right = _evaluate_node(node.right, namespace)
        op = node.op
        if isinstance(op, ast.Add):
            return left + right
        elif isinstance(op, ast.Sub):
            return left - right
        elif isinstance(op, ast.Mult):
            return left * right
        elif isinstance(op, ast.Div):
            return left / right
        elif isinstance(op, ast.Mod):
            return left % right
        elif isinstance(op, ast.Pow):
            return left ** right
        elif isinstance(op, ast.LShift):
            return left << right
        elif isinstance(op, ast.RShift):
            return left >> right
        elif isinstance(op, ast.BitOr):
            return left | right
        elif isinstance(op, ast.BitXor):
            return left ^ right
        elif isinstance(op, ast.BitAnd):
            return left & right
        elif isinstance(op, ast.FloorDiv):
            return left // right
        else:
            raise ValueError(f"Unsupported binary operator: {type(op).__name__}")
    elif isinstance(node, ast.BoolOp):
        op = node.op
        values = node.values
        if isinstance(op, ast.And):
            result = True
            for v in values:
                result = _evaluate_node(v, namespace)
                if not result:
                    return result
            return result
        elif isinstance(op, ast.Or):
            for v in values:
                result = _evaluate_node(v, namespace)
                if result:
                    return result
            return result
        else:
            raise ValueError(f"Unsupported boolean operator: {type(op).__name__}")
    elif isinstance(node, ast.Compare):
        left = _evaluate_node(node.left, namespace)
        ops = node.ops
        comparators = node.comparators
        current = left
        for op, comp in zip(ops, comparators):
            right = _evaluate_node(comp, namespace)
            if isinstance(op, ast.Eq):
                if not (current == right):
                    return False
            elif isinstance(op, ast.NotEq):
                if not (current != right):
                    return False
            elif isinstance(op, ast.Lt):
                if not (current < right):
                    return False
            elif isinstance(op, ast.LtE):
                if not (current <= right):
                    return False
            elif isinstance(op, ast.Gt):
                if not (current > right):
                    return False
            elif isinstance(op, ast.GtE):
                if not (current >= right):
                    return False
            elif isinstance(op, ast.Is):
                if not (current is right):
                    return False
            elif isinstance(op, ast.IsNot):
                if not (current is not right):
                    return False
            elif isinstance(op, ast.In):
                if not (current in right):
                    return False
            elif isinstance(op, ast.NotIn):
                if not (current not in right):
                    return False
            else:
                raise ValueError(f"Unsupported comparison operator: {type(op).__name__}")
            current = right
        return True
    elif isinstance(node, ast.IfExp):
        test = _evaluate_node(node.test, namespace)
        if test:
            return _evaluate_node(node.body, namespace)
        else:
            return _evaluate_node(node.orelse, namespace)
    elif isinstance(node, ast.List):
        return [_evaluate_node(elt, namespace) for elt in node.elts]
    elif isinstance(node, ast.Tuple):
        return tuple(_evaluate_node(elt, namespace) for elt in node.elts)
    elif isinstance(node, ast.Set):
        return {_evaluate_node(elt, namespace) for elt in node.elts}
    elif isinstance(node, ast.Dict):
        keys = [_evaluate_node(k, namespace) for k in node.keys]
        values = [_evaluate_node(v, namespace) for v in node.values]
        return dict(zip(keys, values))
    elif isinstance(node, ast.Subscript):
        value = _evaluate_node(node.value, namespace)
        slice_node = node.slice
        if isinstance(slice_node, ast.Index):
            index = _evaluate_node(slice_node.value, namespace)
            return value[index]
        elif isinstance(slice_node, ast.Slice):
            lower = _evaluate_node(slice_node.lower, namespace) if slice_node.lower is not None else None
            upper = _evaluate_node(slice_node.upper, namespace) if slice_node.upper is not None else None
            step = _evaluate_node(slice_node.step, namespace) if slice_node.step is not None else None
            return value[slice(lower, upper, step)]
        elif isinstance(slice_node, ast.ExtSlice):
            dims = []
            for dim in slice_node.dims:
                if isinstance(dim, ast.Index):
                    dims.append(_evaluate_node(dim.value, namespace))
                elif isinstance(dim, ast.Slice):
                    lower = _evaluate_node(dim.lower, namespace) if dim.lower is not None else None
                    upper = _evaluate_node(dim.upper, namespace) if dim.upper is not None else None
                    step = _evaluate_node(dim.step, namespace) if dim.step is not None else None
                    dims.append(slice(lower, upper, step))
                else:
                    raise ValueError(f"Unsupported slice dimension: {type(dim).__name__}")
            return value[tuple(dims)]
        else:
            raise ValueError(f"Unsupported subscript slice: {type(slice_node).__name__}")
    elif isinstance(node, ast.NameConstant):  # Python <3.8
        return node.value
    elif isinstance(node, ast.Num):  # Python <3.8
        return node.n
    elif isinstance(node, ast.Str):  # Python <3.8
        return node.s
    elif isinstance(node, ast.Bytes):  # Python <3.8
        return node.s
    elif isinstance(node, ast.Ellipsis):
        return Ellipsis
    else:
        raise ValueError(f"Unsupported node type: {type(node).__name__}")

def safe_eval(code_str):
    """Safely evaluate a Python expression, allowing only basic operations."""
    try:
        tree = ast.parse(code_str, mode='eval')
    except SyntaxError:
        raise ValueError("Invalid syntax")
    _check_node(tree)
    # Evaluate using our custom safe evaluator instead of eval()
    return _evaluate_node(tree.body, SAFE_BUILTINS)

