import ast
import operator

def evalInput(inputStr):
    """
    Safely evaluate a restricted Python expression.
    Only literals, basic arithmetic/comparison/logical operators,
    and calls to a whitelist of built-in functions are allowed.
    Attribute access and arbitrary name lookups are forbidden.
    """
    safe_builtins = {
        'abs': abs, 'all': all, 'any': any, 'ascii': ascii, 'bin': bin, 'bool': bool,
        'bytearray': bytearray, 'bytes': bytes, 'callable': callable, 'chr': chr,
        'classmethod': classmethod, 'complex': complex, 'dict': dict, 'divmod': divmod,
        'enumerate': enumerate, 'filter': filter, 'float': float, 'format': format,
        'frozenset': frozenset, 'hash': hash, 'hex': hex, 'int': int,
        'isinstance': isinstance, 'issubclass': issubclass, 'iter': iter, 'len': len,
        'list': list, 'map': map, 'max': max, 'min': min, 'next': next, 'oct': oct,
        'ord': ord, 'pow': pow, 'print': print, 'property': property, 'range': range,
        'repr': repr, 'reversed': reversed, 'round': round, 'set': set, 'slice': slice,
        'sorted': sorted, 'staticmethod': staticmethod, 'str': str, 'sum': sum,
        'tuple': tuple, 'zip': zip, 'True': True, 'False': False, 'None': None,
        'Ellipsis': Ellipsis, 'NotImplemented': NotImplemented
    }

    # Allowed binary operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.LShift: operator.lshift,
        ast.RShift: operator.rshift,
        ast.BitOr: operator.or_,
        ast.BitXor: operator.xor,
        ast.BitAnd: operator.and_,
    }

    # Allowed comparison operators
    cmp_operators = {
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.Is: operator.is_,
        ast.IsNot: operator.is_not,
        ast.In: lambda a, b: a in b,
        ast.NotIn: lambda a, b: a not in b,
    }

    # Allowed unary operators
    unary_operators = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Not: operator.not_,
        ast.Invert: operator.inv,
    }

    def _eval(node):
        """Recursively evaluate a safe AST node."""
        if isinstance(node, ast.Expression):
            return _eval(node.body)

        # Literals
        if isinstance(node, ast.Constant):
            return node.value
        # In Python 3.8+, Num, Str, Bytes, NameConstant, Ellipsis are all Constant
        # For older Python, we handle them separately (but we'll assume 3.8+)
        # We'll keep the old node types for compatibility just in case.
        if isinstance(node, ast.Num):
            return node.n
        if isinstance(node, ast.Str):
            return node.s
        if isinstance(node, ast.Bytes):
            return node.s
        if isinstance(node, ast.NameConstant):
            return node.value

        # Name lookup: only allowed names from safe_builtins
        if isinstance(node, ast.Name):
            if node.id in safe_builtins:
                return safe_builtins[node.id]
            raise ValueError(f"Name '{node.id}' is not allowed")

        # Unary operators
        if isinstance(node, ast.UnaryOp):
            op_func = unary_operators.get(type(node.op))
            if op_func is None:
                raise ValueError(f"Unary operator {type(node.op).__name__} not allowed")
            operand = _eval(node.operand)
            return op_func(operand)

        # Binary operators
        if isinstance(node, ast.BinOp):
            op_func = operators.get(type(node.op))
            if op_func is None:
                raise ValueError(f"Binary operator {type(node.op).__name__} not allowed")
            left = _eval(node.left)
            right = _eval(node.right)
            return op_func(left, right)

        # Boolean operators (and, or)
        if isinstance(node, ast.BoolOp):
            if isinstance(node.op, ast.And):
                result = True
                for value in node.values:
                    if not _eval(value):
                        return False
                return True
            elif isinstance(node.op, ast.Or):
                for value in node.values:
                    if _eval(value):
                        return True
                return False
            else:
                raise ValueError("Unsupported boolean operator")

        # Comparisons
        if isinstance(node, ast.Compare):
            left = _eval(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                right = _eval(comparator)
                op_func = cmp_operators.get(type(op))
                if op_func is None:
                    raise ValueError(f"Comparison operator {type(op).__name__} not allowed")
                if not op_func(left, right):
                    return False
                left = right  # for chained comparisons
            return True

        # Conditional expression (if-else)
        if isinstance(node, ast.IfExp):
            test = _eval(node.test)
            if test:
                return _eval(node.body)
            else:
                return _eval(node.orelse)

        # Function calls (only to allowed names)
        if isinstance(node, ast.Call):
            # Only allow calls to simple names (no attribute calls like obj.method)
            if not isinstance(node.func, ast.Name):
                raise ValueError("Only calls to simple names are allowed")
            func_name = node.func.id
            if func_name not in safe_builtins:
                raise ValueError(f"Function '{func_name}' is not allowed")
            func = safe_builtins[func_name]
            args = [_eval(arg) for arg in node.args]
            # For simplicity, we do not support keyword arguments in this restricted evaluator.
            # If needed, they could be added with similar safety checks.
            if node.keywords:
                raise ValueError("Keyword arguments are not allowed")
            return func(*args)

        # Subscript (indexing) – only allowed on literal containers
        if isinstance(node, ast.Subscript):
            value = _eval(node.value)
            # Only allow subscript on safe built-in types: list, tuple, dict, str, bytes
            if not isinstance(value, (list, tuple, dict, str, bytes)):
                raise ValueError("Subscript only allowed on lists, tuples, dicts, strings, or bytes")
            # The slice/index must be a literal or a simple name (constant)
            if isinstance(node.slice, ast.Index):
                # Python < 3.9 style
                index = _eval(node.slice.value)
            elif isinstance(node.slice, ast.Constant):
                # Python 3.9+ style
                index = node.slice.value
            else:
                raise ValueError("Subscript index must be a constant")
            return value[index]

        # List, Tuple, Set, Dict displays
        if isinstance(node, ast.List):
            return [_eval(elt) for elt in node.elts]
        if isinstance(node, ast.Tuple):
            return tuple(_eval(elt) for elt in node.elts)
        if isinstance(node, ast.Set):
            return {_eval(elt) for elt in node.elts}
        if isinstance(node, ast.Dict):
            return {_eval(k): _eval(v) for k, v in zip(node.keys, node.values)}

        # Everything else is forbidden
        raise ValueError(f"Unsupported expression type: {type(node).__name__}")

    try:
        tree = ast.parse(inputStr, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression: {e}")

    return _eval(tree)

def checkAdminPassword(password):
    if not isinstance(password, str):
        return False
    if len(password) < 12:
        return False
    has_upper = any(c.isupper() for c in password)
    has_lower = any(c.islower() for c in password)
    has_digit = any(c.isdigit() for c in password)
    has_special = any(not c.isalnum() for c in password)
    return has_upper and has_lower and has_digit and has_special

